const insight = ($input.first().json.data || [])[0] || {};
const actions = insight.actions || [];
const findAction = (type) => Number((actions.find(a => a.action_type === type) || {}).value || 0);

const spent = Number(insight.spend || 0);
const leads = findAction('lead') || findAction('onsite_conversion.lead_grouped');
const dms = findAction('onsite_conversion.messaging_conversation_started_7d');
const cpl = leads ? Number((spent / leads).toFixed(2)) : null;

return [{ json: {
  campaign_id: $('Campaña a sincronizar').first().json.campaign_id,
  spent,
  reach: Number(insight.reach || 0),
  impressions: Number(insight.impressions || 0),
  clicks: Number(insight.clicks || 0),
  dms,
  leads,
  cpl,
} }];
